import {range} from '../utils';

export default class AATLookupTable {
  constructor(table) {
    this.table = table;
  }

  lookup(glyph) {
    switch (this.table.version) {
      case 0: // simple array format
        return this.table.values.getItem(glyph);

      case 2: // segment format
      case 4: {
        let min = 0;
